function Logger(constructor: Function) {
  console.log(`Class created: ${constructor.name}`);
}

@Logger
class Person {
  constructor(public name: string) {}
}

const p = new Person('Alice'); // Console: Class created: Person

function LogMethod(
  target: any,
  propertyName: string,
  descriptor: PropertyDescriptor
) {
  const method = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log(`Calling ${propertyName} with`, args);
    return method.apply(this, args);
  };
}

class Calculator {
  @LogMethod
  add(a: number, b: number): number {
    return a + b;
  }
}

const calc = new Calculator();
calc.add(2, 3); // Console: Calling add with [2,3]

function ReadOnly(target: any, propertyKey: string) {
  Object.defineProperty(target, propertyKey, {
    writable: false,
    configurable: false
  });
}

class User {
  @ReadOnly
  role = 'user';
}

const user = new User();
user.role = 'admin'; // This assignment will silently fail in strict mode

function LogParameter(target: any, methodName: string, parameterIndex: number) {
  console.log(`Parameter at position ${parameterIndex} in method ${methodName} has a decorator.`);
}

class Greeter {
  greet(@LogParameter message: string) {
    console.log(message);
  }
}

const greeter = new Greeter();
greeter.greet('Hello!');

function Debounce(delay: number = 300) {
  return function (
    target: any,
    propertyKey: string,
    descriptor: PropertyDescriptor
  ) {
    const originalMethod = descriptor.value;
    let timeoutId: any;
    descriptor.value = function (...args: any[]) {
      clearTimeout(timeoutId);
      timeoutId = setTimeout(() => {
        originalMethod.apply(this, args);
      }, delay);
    };
  };
}

class Search {
  @Debounce(500)
  query(term: string) {
    console.log(`Searching for ${term}`);
  }
}

const search = new Search();
search.query('TypeScript');
